  1→import { format } from 'date-fns';
  2→import { CheckCircle2Icon, XCircleIcon, Loader2Icon } from 'lucide-react';
  3→import { cn } from '@/lib/utils';
  4→import { useBookingStore } from '@/Stores/useBookingStore';
  5→import { useBookingStatus } from '@/hooks/useBookingStatus';
  6→import { calculateNights, calculatePrice } from '@/lib/utils/calculatePrice';
  7→import { formatCurrency } from '@/lib/utils/formatCurrency';
  8→import { Button } from '@/Components/ui/button';
  9→import { Card, CardContent, CardHeader, CardTitle } from '@/Components/ui/card';
 10→import { Separator } from '@/Components/ui/separator';
 11→import type { PropertyData } from '@/types/property';
 12→
 13→interface StatusStepProps {
 14→  propertyData: PropertyData;
 15→}
 16→
 17→export function StatusStep({ propertyData }: StatusStepProps) {
 18→  const { bookingId, checkIn, checkOut, rooms, goToStep, reset } =
 19→    useBookingStore();
 20→  const { status, confirmationId, isPolling } = useBookingStatus(bookingId);
 21→  const { units, property } = propertyData;
 22→  const nights = checkIn && checkOut ? calculateNights(checkIn, checkOut) : 0;
 23→  const breakdown = calculatePrice(rooms, units, nights, property.tax_rate);
 24→
 25→  const handleTryAgain = () => {
 26→    goToStep(3);
 27→  };
 28→
 29→  const handleNewBooking = () => {
 30→    reset();
 31→  };
 32→
 33→  // Pending state
 34→  if (status === 'pending' || isPolling) {
 35→    return (
 36→      <div className={cn('flex flex-col items-center justify-center space-y-4 py-12')}>
 37→        <Loader2Icon className={cn('h-12 w-12 animate-spin text-primary')} />
 38→        <h2 className={cn('text-xl font-semibold')}>Processing your booking...</h2>
 39→        <p className={cn('text-sm text-muted-foreground')}>
 40→          This may take a moment. Please do not close this page.
 41→        </p>
 42→      </div>
 43→    );
 44→  }
 45→
 46→  // Failed state
 47→  if (status === 'failed') {
 48→    return (
 49→      <div className={cn('flex flex-col items-center justify-center space-y-4 py-12')}>
 50→        <XCircleIcon className={cn('h-12 w-12 text-destructive')} />
 51→        <h2 className={cn('text-xl font-semibold')}>Booking failed</h2>
 52→        <p className={cn('text-sm text-muted-foreground')}>
 53→          Something went wrong while processing your booking. Please try again.
 54→        </p>
 55→        <div className={cn('flex gap-3')}>
 56→          <Button variant="outline" size="lg" onClick={handleNewBooking}>
 57→            Start Over
 58→          </Button>
 59→          <Button size="lg" onClick={handleTryAgain}>
 60→            Try Again
 61→          </Button>
 62→        </div>
 63→      </div>
 64→    );
 65→  }
 66→
 67→  // Confirmed state
 68→  return (
 69→    <div className={cn('space-y-6')}>
 70→      <div className={cn('flex flex-col items-center space-y-4 py-8')}>
 71→        <CheckCircle2Icon className={cn('h-12 w-12 text-green-600')} />
 72→        <h2 className={cn('text-xl font-semibold')}>Booking confirmed!</h2>
 73→        {confirmationId && (
 74→          <p className={cn('text-sm text-muted-foreground')}>
 75→            Confirmation ID:{' '}
 76→            <span className={cn('font-mono font-medium text-foreground')}>
 77→              {confirmationId}
 78→            </span>
 79→          </p>
 80→        )}
 81→      </div>
 82→
 83→      <Card>
 84→        <CardHeader>
 85→          <CardTitle>Booking Summary</CardTitle>
 86→        </CardHeader>
 87→        <CardContent className={cn('space-y-4')}>
 88→          <div className={cn('grid grid-cols-2 gap-4')}>
 89→            <div>
 90→              <p className={cn('text-sm text-muted-foreground')}>Check-in</p>
 91→              <p className={cn('font-medium')}>
 92→                {checkIn ? format(new Date(checkIn), 'PPP') : '-'}
 93→              </p>
 94→            </div>
 95→            <div>
 96→              <p className={cn('text-sm text-muted-foreground')}>Check-out</p>
 97→              <p className={cn('font-medium')}>
 98→                {checkOut ? format(new Date(checkOut), 'PPP') : '-'}
 99→              </p>
100→            </div>
101→          </div>
102→
103→          <Separator />
104→
105→          {breakdown.lineItems.map((item) => (
106→            <div
107→              key={item.unitName}
108→              className={cn('flex items-center justify-between text-sm')}
109→            >
110→              <span>
111→                {item.unitName} x {item.quantity}
112→              </span>
113→              <span className={cn('font-medium')}>
114→                {formatCurrency(item.lineTotal)}
115→              </span>
116→            </div>
117→          ))}
118→
119→          <Separator />
120→
121→          <div className={cn('flex justify-between text-lg font-semibold')}>
122→            <span>Total</span>
123→            <span>{formatCurrency(breakdown.total)}</span>
124→          </div>
125→        </CardContent>
126→      </Card>
127→
128→      <div className={cn('flex justify-center')}>
129→        <Button size="lg" onClick={handleNewBooking}>
130→          Make Another Booking
131→        </Button>
132→      </div>
133→    </div>
134→  );
135→}
