  1→import { useState } from 'react';
  2→import { router } from '@inertiajs/react';
  3→import { Link } from '@inertiajs/react';
  4→import { format } from 'date-fns';
  5→import { InfoIcon, LogInIcon, Loader2Icon } from 'lucide-react';
  6→import { cn } from '@/lib/utils';
  7→import { useBookingStore } from '@/Stores/useBookingStore';
  8→import { calculateNights, calculatePrice } from '@/lib/utils/calculatePrice';
  9→import { formatCurrency } from '@/lib/utils/formatCurrency';
 10→import { Button } from '@/Components/ui/button';
 11→import { Card, CardContent, CardHeader, CardTitle } from '@/Components/ui/card';
 12→import { Textarea } from '@/Components/ui/textarea';
 13→import { Label } from '@/Components/ui/label';
 14→import { Separator } from '@/Components/ui/separator';
 15→import { Alert, AlertTitle, AlertDescription } from '@/Components/ui/alert';
 16→import {
 17→  Tooltip,
 18→  TooltipContent,
 19→  TooltipProvider,
 20→  TooltipTrigger,
 21→} from '@/Components/ui/tooltip';
 22→import type { PropertyData } from '@/types/property';
 23→import type { User } from '@/types';
 24→
 25→const MAX_SPECIAL_REQUESTS_LENGTH = 500;
 26→
 27→interface SummaryStepProps {
 28→  propertyData: PropertyData;
 29→  auth: { user: User | null };
 30→}
 31→
 32→export function SummaryStep({ propertyData, auth }: SummaryStepProps) {
 33→  const {
 34→    checkIn,
 35→    checkOut,
 36→    rooms,
 37→    specialRequests,
 38→    setSpecialRequests,
 39→    setBookingId,
 40→    prevStep,
 41→    goToStep,
 42→  } = useBookingStore();
 43→
 44→  const [isSubmitting, setIsSubmitting] = useState(false);
 45→  const [error, setError] = useState<string | null>(null);
 46→
 47→  const { units, property } = propertyData;
 48→  const nights = checkIn && checkOut ? calculateNights(checkIn, checkOut) : 0;
 49→  const breakdown = calculatePrice(rooms, units, nights, property.tax_rate);
 50→  const isAuthenticated = !!auth.user;
 51→
 52→  const handleConfirm = () => {
 53→    if (!checkIn || !checkOut || !isAuthenticated) return;
 54→
 55→    setIsSubmitting(true);
 56→    setError(null);
 57→
 58→    router.post(
 59→      '/bookings',
 60→      {
 61→        checkIn,
 62→        checkOut,
 63→        rooms: rooms.map((r) => ({
 64→          unitId: r.unitId,
 65→          quantity: r.quantity,
 66→          guests: r.guests,
 67→        })),
 68→        specialRequests,
 69→        submitted_total: breakdown.total,
 70→      },
 71→      {
 72→        onSuccess: (page) => {
 73→          // The booking ID should be in the response flash or props
 74→          const bookingId = (page.props as Record<string, unknown>).bookingId as number | undefined;
 75→          if (bookingId) {
 76→            setBookingId(bookingId);
 77→          }
 78→          goToStep(5);
 79→        },
 80→        onError: (errors) => {
 81→          setIsSubmitting(false);
 82→          // 422 validation errors
 83→          const messages = Object.values(errors);
 84→          setError(messages.join('. '));
 85→        },
 86→        onFinish: () => {
 87→          setIsSubmitting(false);
 88→        },
 89→      }
 90→    );
 91→  };
 92→
 93→  return (
 94→    <div className={cn('space-y-6')}>
 95→      <h2 className={cn('text-xl font-semibold')}>Review your booking</h2>
 96→
 97→      <Card>
 98→        <CardHeader>
 99→          <CardTitle>Booking Details</CardTitle>
100→        </CardHeader>
101→        <CardContent className={cn('space-y-4')}>
102→          {/* Dates */}
103→          <div className={cn('grid grid-cols-2 gap-4')}>
104→            <div>
105→              <p className={cn('text-sm text-muted-foreground')}>Check-in</p>
106→              <p className={cn('font-medium')}>
107→                {checkIn ? format(new Date(checkIn), 'PPP') : '-'}
108→              </p>
109→            </div>
110→            <div>
111→              <p className={cn('text-sm text-muted-foreground')}>Check-out</p>
112→              <p className={cn('font-medium')}>
113→                {checkOut ? format(new Date(checkOut), 'PPP') : '-'}
114→              </p>
115→            </div>
116→          </div>
117→          <p className={cn('text-sm text-muted-foreground')}>
118→            {nights} {nights === 1 ? 'night' : 'nights'}
119→          </p>
120→
121→          <Separator />
122→
123→          {/* Room breakdown */}
124→          <div className={cn('space-y-3')}>
125→            <p className={cn('font-medium')}>Rooms</p>
126→            {breakdown.lineItems.map((item) => (
127→              <div
128→                key={item.unitName}
129→                className={cn('flex items-center justify-between text-sm')}
130→              >
131→                <div>
132→                  <p className={cn('font-medium')}>{item.unitName}</p>
133→                  <p className={cn('text-muted-foreground')}>
134→                    {item.quantity} {item.quantity === 1 ? 'room' : 'rooms'}
135→                    {item.pricingModel === 'per_person' &&
136→                      `, ${item.guests} ${item.guests === 1 ? 'guest' : 'guests'} each`}
137→                    {' x '}
138→                    {item.nights} {item.nights === 1 ? 'night' : 'nights'}
139→                  </p>
140→                </div>
141→                <p className={cn('font-medium')}>{formatCurrency(item.lineTotal)}</p>
142→              </div>
143→            ))}
144→          </div>
145→
146→          <Separator />
147→
148→          {/* Price totals */}
149→          <div className={cn('space-y-1')}>
150→            <div className={cn('flex justify-between text-sm')}>
151→              <span className={cn('text-muted-foreground')}>Subtotal</span>
152→              <span>{formatCurrency(breakdown.subtotal)}</span>
153→            </div>
154→            <div className={cn('flex justify-between text-sm')}>
155→              <span className={cn('text-muted-foreground')}>
156→                VAT ({(breakdown.taxRate * 100).toFixed(0)}%)
157→              </span>
158→              <span>{formatCurrency(breakdown.taxAmount)}</span>
159→            </div>
160→            <Separator />
161→            <div className={cn('flex items-center justify-between text-lg font-semibold')}>
162→              <span>Total</span>
163→              <TooltipProvider>
164→                <Tooltip>
165→                  <TooltipTrigger asChild>
166→                    <span className={cn('flex cursor-help items-center gap-1')}>
167→                      {formatCurrency(breakdown.total)}
168→                      <InfoIcon className={cn('h-4 w-4 text-muted-foreground')} />
169→                    </span>
170→                  </TooltipTrigger>
171→                  <TooltipContent>
172→                    Includes 15% VAT ({formatCurrency(breakdown.taxAmount)})
173→                  </TooltipContent>
174→                </Tooltip>
175→              </TooltipProvider>
176→            </div>
177→          </div>
178→        </CardContent>
179→      </Card>
180→
181→      {/* Special requests */}
182→      <div className={cn('space-y-2')}>
183→        <Label htmlFor="specialRequests">
184→          Special requests (optional)
185→        </Label>
186→        <Textarea
187→          id="specialRequests"
188→          value={specialRequests}
189→          onChange={(e) => setSpecialRequests(e.target.value.slice(0, MAX_SPECIAL_REQUESTS_LENGTH))}
190→          placeholder="Any special requirements or requests..."
191→          maxLength={MAX_SPECIAL_REQUESTS_LENGTH}
192→          aria-describedby="specialRequests-count"
193→        />
194→        <p
195→          id="specialRequests-count"
196→          className={cn('text-xs text-muted-foreground')}
197→        >
198→          {specialRequests.length}/{MAX_SPECIAL_REQUESTS_LENGTH} characters
199→        </p>
200→      </div>
201→
202→      {/* Auth gate */}
203→      {!isAuthenticated && (
204→        <Alert>
205→          <LogInIcon className={cn('h-4 w-4')} />
206→          <AlertTitle>Sign in to complete your booking</AlertTitle>
207→          <AlertDescription>
208→            You need to be logged in to submit a booking. Your selections will
209→            be saved.{' '}
210→            <Link href="/login" className={cn('font-medium underline')}>
211→              Log in
212→            </Link>{' '}
213→            or{' '}
214→            <Link href="/sign-up" className={cn('font-medium underline')}>
215→              create an account
216→            </Link>
217→            .
218→          </AlertDescription>
219→        </Alert>
220→      )}
221→
222→      {/* Error display */}
223→      {error && (
224→        <Alert variant="destructive">
225→          <AlertTitle>Booking failed</AlertTitle>
226→          <AlertDescription>{error}</AlertDescription>
227→        </Alert>
228→      )}
229→
230→      <div className={cn('flex justify-between')}>
231→        <Button
232→          type="button"
233→          variant="outline"
234→          size="lg"
235→          onClick={prevStep}
236→          disabled={isSubmitting}
237→        >
238→          Back
239→        </Button>
240→        {isAuthenticated && (
241→          <Button
242→            type="button"
243→            size="lg"
244→            onClick={handleConfirm}
245→            disabled={isSubmitting}
246→          >
247→            {isSubmitting ? (
248→              <>
249→                <Loader2Icon className={cn('mr-2 h-4 w-4 animate-spin')} />
250→                Submitting...
251→              </>
252→            ) : (
253→              'Confirm Booking'
254→            )}
255→          </Button>
256→        )}
257→      </div>
258→    </div>
259→  );
260→}
